import React, { useState } from 'react';
import { Copy, Check, X, CheckCircle, User, Mail, Key, ShieldAlert, Info, ArrowRight, Zap, Ban, AlertTriangle, RefreshCw } from 'lucide-react';
import { Task } from '../types.ts';

interface TaskAssignmentProps {
  task: Task;
  onComplete: () => void;
  onCancel: () => void;
}

type VerificationStatus = 'idle' | 'verifying' | 'failed';

const TaskAssignment: React.FC<TaskAssignmentProps> = ({ task, onComplete, onCancel }) => {
  const [copiedField, setCopiedField] = useState<string | null>(null);
  const [status, setStatus] = useState<VerificationStatus>('idle');

  const copyToClipboard = (text: string, field: string) => {
    navigator.clipboard.writeText(text);
    setCopiedField(field);
    setTimeout(() => setCopiedField(null), 2000);
  };

  const handleInitialSubmit = () => {
    setStatus('verifying');
    // Simulate server-side verification check
    setTimeout(() => {
      setStatus('failed');
    }, 3000);
  };

  const handleFinalSubmit = () => {
    setStatus('verifying');
    // On the second attempt, we "succeed" for demo purposes
    setTimeout(() => {
      onComplete();
    }, 2500);
  };

  const FieldRow = ({ label, value, icon, copyable, fieldId, subLabel }: any) => (
    <div 
      className={`relative group flex flex-col p-4 rounded-xl transition-all ${
        copyable 
        ? 'cursor-pointer hover:bg-slate-50 active:scale-[0.98]' 
        : 'bg-white'
      }`}
      onClick={() => copyable && copyToClipboard(value, fieldId)}
    >
      <div className="flex items-center justify-between mb-1">
        <div className="flex items-center gap-2">
          <div className="text-blue-500">
            {icon}
          </div>
          <span className="text-sm font-bold text-gray-800">{label}:</span>
          {copyable && (
            <span className="text-[11px] text-slate-500 font-medium ml-1">
              (কপি করতে ট্যাপ করুন)
            </span>
          )}
        </div>
        {subLabel && (
          <span className="flex items-center gap-1 text-[10px] bg-indigo-100 text-indigo-700 px-2 py-0.5 rounded-full font-black uppercase tracking-tighter animate-pulse">
            <Zap className="w-2.5 h-2.5" />
            {subLabel}
          </span>
        )}
      </div>
      <div className="flex items-center gap-2">
        <div className="bg-blue-500 p-1 rounded-sm text-white">
          <ArrowRight className="w-3 h-3" />
        </div>
        <p className="text-lg font-mono font-medium text-slate-700 tracking-tight break-all">:- {value}</p>
        {copiedField === fieldId && (
          <div className="absolute right-4 top-1/2 -translate-y-1/2 bg-green-500 text-white text-[10px] px-2 py-1 rounded font-bold animate-in fade-in zoom-in">
            COPIED!
          </div>
        )}
      </div>
    </div>
  );

  if (status === 'verifying') {
    return (
      <div className="w-full max-w-lg mx-auto px-4 mt-8 animate-in fade-in duration-300">
        <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden p-12 flex flex-col items-center justify-center gap-6">
          <div className="relative">
            <div className="w-20 h-20 border-4 border-slate-100 rounded-full"></div>
            <div className="absolute top-0 left-0 w-20 h-20 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
          </div>
          <div className="text-center">
            <h3 className="text-xl font-black text-slate-900 mb-2">সার্ভার ভেরিফিকেশন চলছে...</h3>
            <p className="text-sm text-slate-500 font-medium px-8">আমরা আপনার জিমেইলটি গুগল ডাটাবেসে চেক করছি। অনুগ্রহ করে অপেক্ষা করুন।</p>
          </div>
          <div className="flex items-center gap-2 px-4 py-2 bg-indigo-50 rounded-full">
            <ShieldAlert className="w-4 h-4 text-indigo-600 animate-pulse" />
            <span className="text-[10px] font-black text-indigo-600 uppercase tracking-widest">SST-SECURE ENCRYPTION ACTIVE</span>
          </div>
        </div>
      </div>
    );
  }

  if (status === 'failed') {
    return (
      <div className="w-full max-w-lg mx-auto px-4 mt-8 animate-in zoom-in-95 duration-300">
        <div className="bg-white rounded-3xl shadow-2xl border-2 border-rose-100 overflow-hidden text-left relative">
          {/* Failed Header */}
          <div className="px-6 py-5 border-b border-rose-50 bg-rose-50/30 flex items-center gap-3">
             <div className="bg-rose-500 p-2 rounded-full">
                <X className="w-6 h-6 text-white" strokeWidth={3} />
             </div>
             <h2 className="text-2xl font-black text-rose-600 tracking-tight">ভেরিফিকেশন ব্যর্থ!</h2>
          </div>

          <div className="p-6 space-y-5">
            <div className="flex items-center gap-2 text-lg font-bold text-gray-800">
              <span className="text-2xl">👇</span> নিচের তথ্য দিয়ে জিমেইল খুলুন:
            </div>

            <div className="space-y-3 bg-slate-50/50 rounded-2xl p-5 border border-slate-100">
               <div className="flex items-start gap-3">
                  <User className="w-5 h-5 text-slate-400 mt-1" />
                  <div>
                    <p className="text-base font-bold text-gray-800">First Name:- <span className="font-mono text-slate-600 ml-1">{task.firstName}</span></p>
                    <p className="text-base font-bold text-gray-800">Last Name:- <span className="font-mono text-slate-600 ml-1">{task.lastName}</span></p>
                  </div>
               </div>

               <div className="flex items-center gap-3">
                  <Mail className="w-5 h-5 text-slate-400" />
                  <p className="text-base font-bold text-gray-800">Gmail: <span className="font-mono text-slate-600 ml-1">{task.gmail}</span></p>
               </div>

               <div className="flex items-center gap-3">
                  <Key className="w-5 h-5 text-slate-400" />
                  <p className="text-base font-bold text-gray-800">Password: <span className="font-mono text-slate-600 ml-1">{task.password}</span></p>
               </div>

               <div className="flex items-center gap-3">
                  <ShieldAlert className="w-5 h-5 text-slate-400" />
                  <p className="text-base font-bold text-gray-800">Recovery Mail: <span className="font-mono text-slate-600 ml-1 text-xs">{task.recovery}</span></p>
               </div>
            </div>

            {/* ERROR BOX MATCHING IMAGE */}
            <div className="p-5 bg-amber-50 rounded-2xl border-2 border-amber-200">
              <div className="flex gap-3">
                <AlertTriangle className="w-6 h-6 text-amber-600 shrink-0" />
                <div className="space-y-1">
                  <p className="text-base font-black text-amber-900 leading-tight">সমস্যা:</p>
                  <p className="text-[13px] font-bold text-amber-800 leading-relaxed">
                    এই নামে কোনো জিমেইল একাউন্ট তৈরি করা হয়নি বা গুগল সার্ভারে পাওয়া যাচ্ছে না। 
                    অনুগ্রহ করে একাউন্টটি সঠিকভাবে তৈরি করুন এবং আবার চেষ্টা করুন।
                  </p>
                </div>
              </div>
            </div>
          </div>

          {/* Action Buttons */}
          <div className="grid grid-cols-1 gap-2 p-4 bg-slate-100 border-t border-slate-200">
            <button 
              onClick={handleFinalSubmit}
              className="flex items-center justify-center gap-3 py-5 bg-emerald-600 text-white rounded-2xl font-black text-xl hover:bg-emerald-700 transition-all active:scale-95 shadow-xl shadow-emerald-100"
            >
              <CheckCircle className="w-6 h-6" />
              <span>সম্পন্ন হয়েছে</span>
            </button>

            <button 
              onClick={onCancel}
              className="flex items-center justify-center gap-2 py-3 text-rose-600 font-bold text-base hover:bg-rose-50 rounded-xl transition-all"
            >
              <X className="w-5 h-5" />
              বাতিল করুন
            </button>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="w-full max-w-lg mx-auto px-4 mt-8 animate-in slide-in-from-bottom-8 duration-500">
      <div className="bg-white rounded-3xl shadow-2xl border border-slate-200 overflow-hidden text-left relative">
        {/* Header Section */}
        <div className="px-6 py-4 border-b border-slate-100 bg-indigo-50/30 flex items-center justify-between">
          <div className="flex items-center gap-3">
             <span className="text-2xl">📋</span>
             <h2 className="text-xl font-black text-slate-900 tracking-tight">নতুন কাজ বরাদ্দ</h2>
          </div>
          <div className="text-[10px] font-black bg-indigo-600 text-white px-3 py-1 rounded-full uppercase tracking-widest">
            ACTIVE
          </div>
        </div>

        <div className="p-6 space-y-4">
          <div className="flex items-center gap-2 text-lg font-bold text-gray-800 mb-2">
            <span className="text-2xl">👇</span> নিচের তথ্য দিয়ে জিমেইল খুলুন:
          </div>

          <div className="space-y-1 bg-slate-50/50 rounded-2xl p-2 border border-slate-100">
             <div className="flex items-center gap-2 p-4">
                <div className="text-indigo-500"><User className="w-5 h-5" /></div>
                <div className="flex flex-col">
                   <p className="text-sm font-bold text-gray-800">First Name:- <span className="font-mono text-slate-600 ml-1">{task.firstName}</span></p>
                   <p className="text-sm font-bold text-gray-800">Last Name:- <span className="font-mono text-slate-600 ml-1">{task.lastName}</span></p>
                </div>
             </div>

            <FieldRow 
              label="Gmail" 
              value={task.gmail} 
              icon={<Mail className="w-5 h-5" />} 
              copyable 
              fieldId="gmail"
            />

            <FieldRow 
              label="Password" 
              value={task.password} 
              icon={<Key className="w-5 h-5" />} 
              copyable 
              fieldId="pass"
            />

            <FieldRow 
              label="Recovery Mail" 
              value={task.recovery} 
              icon={<ShieldAlert className="w-5 h-5" />} 
              fieldId="recovery"
              copyable
              subLabel="AUTO"
            />
          </div>

          {/* Rules Section */}
          <div className="mt-6 p-5 bg-amber-50 rounded-2xl border border-amber-100">
            <div className="flex items-center gap-2 mb-3 text-amber-700 font-black">
              <span className="text-xl">⚠️</span> নিয়মাবলী:
            </div>
            <ul className="space-y-2 text-[13px] font-bold text-amber-900/70 leading-relaxed">
              <li className="flex gap-2"><span>•</span> তথ্যগুলো কপি করে সঠিকভাবে জিমেইল খুলুন।</li>
              <li className="flex gap-2"><span>•</span> সম্পন্ন হলে অটোমেটিক টেলিগ্রাম শেয়ার হবে।</li>
              <li className="flex gap-2"><span>•</span> কোনো ভুল তথ্য দিলে পেমেন্ট পাবেন না।</li>
            </ul>
          </div>
        </div>

        {/* Action Buttons */}
        <div className="grid grid-cols-1 gap-2 p-4 bg-slate-100 border-t border-slate-200">
          <button 
            onClick={handleInitialSubmit}
            className="group flex items-center justify-center gap-3 py-5 bg-indigo-600 text-white rounded-2xl font-black text-xl hover:bg-indigo-700 transition-all active:scale-95 shadow-xl shadow-indigo-100"
          >
            <CheckCircle className="w-6 h-6" />
            <span>সাবমিট করুন</span>
            <ArrowRight className="w-5 h-5 group-hover:translate-x-1 transition-transform" />
          </button>

          <button 
            onClick={onCancel}
            className="flex items-center justify-center gap-2 py-3 text-rose-600 font-bold text-sm hover:bg-rose-50 rounded-xl transition-all"
          >
            <X className="w-4 h-4" />
            বাতিল করুন
          </button>
        </div>
      </div>
      <p className="text-center text-[10px] text-slate-400 mt-4 font-bold uppercase tracking-widest">
        SECURE SUBMISSION SYSTEM • MAHABUB HUB
      </p>
    </div>
  );
};

export default TaskAssignment;
